#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ParseError {
    /// Token had no shift action at the current state.
    SyntaxError { token: u16, state: u16 },
    /// External token was outside [FIRST_TOKEN, FIRST_TOKEN+NTOKEN).
    OutOfRange { token: u16 },
    /// Reduce action attempted on rule index >= NRULE.
    BadReduce { rule: u32 },
    /// Stack underflow during reduce (table corruption).
    StackUnderflow,
}

#[derive(Debug, Clone, Copy, Default)]
struct Frame {
    state: u16,
    major: u16,
    value: Value,
}

/// Calc parser.
pub struct CalcParser {
    stack: Vec<Frame>,
    accepted: bool,
    errored: bool,
    pub final_value: Value,
    /// User argument threaded into ReduceCtx for
    /// every reduce callback.  Populated from
    /// %rust_extra_argument; () when unset.
    pub user: UserArg,
}

impl CalcParser {
    /// Construct a parser with a user-supplied UserArg.
    /// When UserArg is () use new() instead.
    pub fn new_with_user(user: UserArg) -> Self {
        let mut stack = Vec::with_capacity(64);
        stack.push(Frame::default());
        Self {
            stack, accepted: false, errored: false,
            final_value: Value::default(),
            user,
        }
    }

    /// Construct a fresh parser at state 0 with the
    /// UserArg's Default value.
    pub fn new() -> Self where UserArg: Default {
        Self::new_with_user(UserArg::default())
    }

    /// Feed an external token code (with semantic value).
    /// Use 0 as the token code to indicate end-of-input.
    /// Returns Ok on accept-pending or accept; Err on syntax
    /// error or unrecoverable state corruption.
    pub fn push(&mut self, token_code: u16, value: Value)
        -> Result<bool, ParseError>
    {
        if self.accepted { return Ok(true); }
        if self.errored  { return Err(ParseError::SyntaxError {
            token: token_code,
            state: self.top_state(),
        }); }

        // Convert external -> internal: external == internal + FIRST_TOKEN.
        // EOF (0) is preserved; out-of-range yields OutOfRange.
        let mut major: i32 = if token_code == 0 {
            0
        } else {
            (token_code as i32) - (FIRST_TOKEN as i32)
        };
        if major < 0 || major >= (NTOKEN as i32) {
            self.errored = true;
            return Err(ParseError::OutOfRange { token: token_code });
        }

        let mut retried_with_fallback = false;
        loop {
            // Top state.
            let cur_state = self.top_state();
            // Pending shift-reduce: cur_state encoded as a reduce.
            if cur_state >= YY_MIN_REDUCE {
                let ruleno = (cur_state - YY_MIN_REDUCE) as u32;
                match self.reduce(ruleno)? {
                    ReduceOutcome::Continue => continue,
                    ReduceOutcome::Accept => {
                        self.accepted = true;
                        return Ok(true);
                    }
                }
            }

            let action = Self::find_shift_action(cur_state, major as u16);

            // Plain shift: push (action, major) and consume.
            if action <= YY_MAX_SHIFT {
                if token_code == 0 {
                    self.accepted = true;
                    self.on_parse_accept();
                    return Ok(true);
                }
                self.stack.push(Frame {
                    state: action,
                    major: major as u16,
                    value,
                });
                return Ok(false);
            }

            // Shift-reduce: encode the action as a pending reduce
            // (action + MIN_REDUCE - MIN_SHIFTREDUCE).  Next call
            // sees the encoded state and falls into reduce.
            if action <= YY_MAX_SHIFTREDUCE {
                let encoded = action + (YY_MIN_REDUCE - YY_MIN_SHIFTREDUCE);
                self.stack.push(Frame {
                    state: encoded,
                    major: major as u16,
                    value,
                });
                return Ok(false);
            }

            if action == YY_ACCEPT_ACTION {
                self.accepted = true;
                self.on_parse_accept();
                return Ok(true);
            }

            // Reduce.
            if action >= YY_MIN_REDUCE
                && action != YY_ERROR_ACTION
                && action != YY_NO_ACTION
            {
                let ruleno = (action - YY_MIN_REDUCE) as u32;
                match self.reduce(ruleno)? {
                    ReduceOutcome::Continue => continue,
                    ReduceOutcome::Accept => {
                        self.accepted = true;
                        return if token_code == 0 { Ok(true) } else { Ok(false) };
                    }
                }
            }

            // Try fallback once.
            if HAS_FALLBACK
                && !retried_with_fallback
                && major >= 0
                && (major as usize) < YY_FALLBACK.len()
                && YY_FALLBACK[major as usize] != 0
            {
                major = YY_FALLBACK[major as usize] as i32;
                retried_with_fallback = true;
                continue;
            }

            // No action.
            self.errored = true;
            return Err(ParseError::SyntaxError {
                token: token_code,
                state: cur_state,
            });
        }
    }

    /// Feed end-of-input.  Equivalent to push(0, 0).
    pub fn finalize(&mut self) -> Result<bool, ParseError> {
        self.push(0, Value::default())
    }

    /// Hook fired on syntax error.  Override the body via
    /// %rust_syntax_error in the grammar; default is no-op.
    pub fn on_syntax_error(&mut self, _token: u16, _state: u16) {
        /* no-op */
    }

    /// Hook fired on parse accept.  Override via
    /// %rust_parse_accept; default is no-op.
    pub fn on_parse_accept(&mut self) {
        /* no-op */
    }

    /// Hook fired on parse failure (post-error, no recovery).
    /// Override via %rust_parse_failure; default is no-op.
    pub fn on_parse_failure(&mut self) {
        /* no-op */
    }

    /// Hook fired on stack overflow.  In Rust the Vec stack
    /// grows automatically; this is mostly informational.
    /// Override via %rust_stack_overflow; default is no-op.
    pub fn on_stack_overflow(&mut self) {
        /* no-op */
    }

    fn top_state(&self) -> u16 {
        self.stack.last().map(|f| f.state).unwrap_or(0)
    }

    fn find_shift_action(state: u16, lookahead: u16) -> u16 {
        // state passthrough: states above YY_MAX_SHIFT mean
        // pending reduce; caller has already handled those.
        if state as u32 >= NSTATE {
            return state;
        }
        let ofst = YY_SHIFT_OFST[state as usize];
        let idx = ofst + (lookahead as i32);
        if idx < 0 || (idx as usize) >= YY_LOOKAHEAD.len() {
            return YY_DEFAULT[state as usize];
        }
        if YY_LOOKAHEAD[idx as usize] != lookahead {
            return YY_DEFAULT[state as usize];
        }
        YY_ACTION[idx as usize]
    }

    fn reduce(&mut self, ruleno: u32) -> Result<ReduceOutcome, ParseError> {
        if ruleno >= NRULE {
            self.errored = true;
            return Err(ParseError::BadReduce { rule: ruleno });
        }
        let nrhs = -(YY_RULE_NRHS[ruleno as usize] as i32);
        let lhs_sym = YY_RULE_LHS[ruleno as usize] as i32;

        // Snapshot RHS values, build a transient ReduceCtx,
        // call the callback, then mutate the stack.
        // Need at least nrhs frames above the bottom marker.
        if (self.stack.len() as i32) < nrhs + 1 {
            self.errored = true;
            return Err(ParseError::StackUnderflow);
        }
        let split = self.stack.len() - (nrhs as usize);
        let mut lhs_value = Value::default();
        let mut rhs_values: Vec<Value> = self.stack[split..]
            .iter()
            .map(|f| f.value)
            .collect();
        let cb = YY_RULE_REDUCE_FN[ruleno as usize];
        cb(&mut ReduceCtx {
            lhs: &mut lhs_value,
            rhs: &mut rhs_values,
            user: &mut self.user,
        });

        // Pop nrhs frames.
        self.stack.truncate(split);

        // Compute goto state for the LHS non-terminal at the
        // parent state.  When the goto is YY_ACCEPT_ACTION,
        // the start rule has reduced to its bottom-of-stack
        // and we accept.  Mirrors src/parse_engine.c.
        let parent_state = self.top_state();
        let goto = Self::find_goto(parent_state, lhs_sym as u16);
        if goto == YY_ACCEPT_ACTION {
            self.final_value = lhs_value;
            self.on_parse_accept();
            return Ok(ReduceOutcome::Accept);
        }
        if goto == YY_ERROR_ACTION || goto == YY_NO_ACTION {
            self.errored = true;
            self.on_syntax_error(lhs_sym as u16, parent_state);
            return Err(ParseError::SyntaxError {
                token: lhs_sym as u16,
                state: parent_state,
            });
        }
        // Encode shift-reduce range as pending reduce on push.
        let pushed = if goto > YY_MAX_SHIFT && goto <= YY_MAX_SHIFTREDUCE {
            goto + (YY_MIN_REDUCE - YY_MIN_SHIFTREDUCE)
        } else {
            goto
        };
        self.stack.push(Frame {
            state: pushed,
            major: lhs_sym as u16,
            value: lhs_value,
        });
        Ok(ReduceOutcome::Continue)
    }

    fn find_goto(state: u16, lhs: u16) -> u16 {
        if (state as u32) >= NSTATE {
            return state;
        }
        let ofst = YY_REDUCE_OFST[state as usize];
        let idx = ofst + (lhs as i32);
        if idx < 0 || (idx as usize) >= YY_LOOKAHEAD.len() {
            return YY_DEFAULT[state as usize];
        }
        if YY_LOOKAHEAD[idx as usize] != lhs {
            return YY_DEFAULT[state as usize];
        }
        YY_ACTION[idx as usize]
    }
}

impl Default for CalcParser {
    fn default() -> Self { Self::new() }
}

enum ReduceOutcome { Continue, Accept }
